import{c as n}from"./app.8935f5f1.js";const a={},s=n('<h2 id="calendar" tabindex="-1"><a class="header-anchor" href="#calendar" aria-hidden="true">#</a> Calendar</h2><div class="language-java ext-java"><pre class="language-java"><code><span class="token doc-comment comment">/**\n * <span class="token keyword">@author</span> hzqq\n * <span class="token keyword">@descrption</span> 日期时间\n */</span>\n<span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">Caler</span> <span class="token punctuation">{</span>\n\n    <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">void</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token class-name">String</span><span class="token punctuation">[</span><span class="token punctuation">]</span> args<span class="token punctuation">)</span> <span class="token punctuation">{</span>\n        <span class="token class-name">Calendar</span> calendar <span class="token operator">=</span> <span class="token class-name">Calendar</span><span class="token punctuation">.</span><span class="token function">getInstance</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n       <span class="token comment">/*\n        // 获取年\n        int year = calendar.get(Calendar.YEAR);\n\n        // 获取月，这里需要需要月份的范围为0~11，因此获取月份的时候需要+1才是当前月份值\n        int month = calendar.get(Calendar.MONTH) + 1;\n\n        // 获取日\n        int day = calendar.get(Calendar.DAY_OF_MONTH);\n\n        // 获取时\n        int hour = calendar.get(Calendar.HOUR);\n        // int hour = calendar.get(Calendar.HOUR_OF_DAY); // 24小时表示\n\n        // 获取分\n        int minute = calendar.get(Calendar.MINUTE);\n\n        // 获取秒\n        int second = calendar.get(Calendar.SECOND);\n\n        // 星期，英语国家星期从星期日开始计算\n        int weekday = calendar.get(Calendar.DAY_OF_WEEK);\n\n        System.out.println(&quot;现在是&quot; + year + &quot;年&quot; + month + &quot;月&quot; + day + &quot;日&quot; + hour\n                + &quot;时&quot; + minute + &quot;分&quot; + second + &quot;秒&quot; + &quot;星期&quot; + weekday);\n\n*/</span>\n\n\n<span class="token comment">// 设置日期</span>\n        calendar<span class="token punctuation">.</span><span class="token function">set</span><span class="token punctuation">(</span><span class="token class-name">Calendar</span><span class="token punctuation">.</span>YEAR<span class="token punctuation">,</span> <span class="token number">2000</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n        <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;现在是&quot;</span> <span class="token operator">+</span> calendar<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token class-name">Calendar</span><span class="token punctuation">.</span>YEAR<span class="token punctuation">)</span> <span class="token operator">+</span> <span class="token string">&quot;年&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n\n        calendar<span class="token punctuation">.</span><span class="token function">set</span><span class="token punctuation">(</span><span class="token number">2008</span><span class="token punctuation">,</span> <span class="token number">8</span><span class="token punctuation">,</span> <span class="token number">8</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n        <span class="token comment">// 获取年</span>\n        <span class="token keyword">int</span> year <span class="token operator">=</span> calendar<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token class-name">Calendar</span><span class="token punctuation">.</span>YEAR<span class="token punctuation">)</span><span class="token punctuation">;</span>\n\n        <span class="token comment">// 获取月</span>\n        <span class="token keyword">int</span> month <span class="token operator">=</span> calendar<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token class-name">Calendar</span><span class="token punctuation">.</span>MONTH<span class="token punctuation">)</span><span class="token punctuation">;</span>\n\n        <span class="token comment">// 获取日</span>\n        <span class="token keyword">int</span> day <span class="token operator">=</span> calendar<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token class-name">Calendar</span><span class="token punctuation">.</span>DAY_OF_MONTH<span class="token punctuation">)</span><span class="token punctuation">;</span>\n\n        <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;现在是&quot;</span> <span class="token operator">+</span> year <span class="token operator">+</span> <span class="token string">&quot;年&quot;</span> <span class="token operator">+</span> month <span class="token operator">+</span> <span class="token string">&quot;月&quot;</span> <span class="token operator">+</span> day <span class="token operator">+</span> <span class="token string">&quot;日&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n    <span class="token punctuation">}</span>\n<span class="token punctuation">}</span>\n</code></pre></div>',2);a.render=function(n,a){return s};export{a as default};
